import{_ as t,o as a,c as o,ae as d}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Node Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/nodes.md","filePath":"guide/user/nodes.md"}'),i={name:"guide/user/nodes.md"};function n(s,e,r,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="node-management" tabindex="-1">Node Management <a class="header-anchor" href="#node-management" aria-label="Permalink to &quot;Node Management&quot;">​</a></h1><p>Nodes represent compute resources (typically at hospitals or research institutions) that participate in federated analyses. Administrators register and manage nodes through the Hub.</p><h2 id="registration" tabindex="-1">Registration <a class="header-anchor" href="#registration" aria-label="Permalink to &quot;Registration&quot;">​</a></h2><p>Nodes are registered in the Hub with:</p><ul><li>A unique name and identifier</li><li>A public key for secure communication</li><li>Realm assignment (organizational scope)</li><li>Registry project association (for receiving analysis containers)</li></ul><h2 id="node-lifecycle" tabindex="-1">Node Lifecycle <a class="header-anchor" href="#node-lifecycle" aria-label="Permalink to &quot;Node Lifecycle&quot;">​</a></h2><ol><li><strong>Register</strong> — administrator creates the node entry in Hub</li><li><strong>Configure</strong> — node operator sets up credentials and connectivity</li><li><strong>Assign to projects</strong> — nodes are added to projects via <code>ProjectNode</code> associations</li><li><strong>Execute analyses</strong> — the worker distributes analysis containers to assigned nodes</li></ol><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/nodes</code></td><td>List all nodes</td></tr><tr><td><code>GET</code></td><td><code>/nodes/:id</code></td><td>Get node details</td></tr><tr><td><code>POST</code></td><td><code>/nodes</code></td><td>Register a new node</td></tr><tr><td><code>PUT</code></td><td><code>/nodes/:id</code></td><td>Update node</td></tr><tr><td><code>DELETE</code></td><td><code>/nodes/:id</code></td><td>Remove node</td></tr></tbody></table><h2 id="credential-management" tabindex="-1">Credential Management <a class="header-anchor" href="#credential-management" aria-label="Permalink to &quot;Credential Management&quot;">​</a></h2><p>Each node has an <code>account_secret</code> field that is not returned by default in API responses. To retrieve it, the requesting user must have the appropriate permission and explicitly request the field:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /nodes/:id?fields=+account_secret</span></span></code></pre></div><p>This field-level access control is enforced by the Node service&#39;s permission checker.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/guide/user/realms.html">Realms</a> — nodes are scoped to realms</li><li><a href="/guide/user/approval.html">Approval Workflows</a> — how nodes participate in approved projects</li></ul>',15)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
